// Create the daily orchestration event.
const timezone = 'Asia/Taipei';
const language = 'zh-TW';
const dailyLimit = 1;
const now = new Date();

const runDate = new Intl.DateTimeFormat('en-CA', {
  timeZone: timezone,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
}).format(now);

const runId = `daily.run:${runDate}:${Math.random().toString(36).slice(2, 10)}`;

return [
  {
    json: {
      event: 'daily.run',
      runId,
      runDate,
      startedAt: now.toISOString(),
      timezone,
      language,
      dailyLimit,
      metadata: {
        workflow: '01-daily-orchestrator',
        version: '0.1.2',
        status: 'ready',
      },
    },
  },
];
